module top_module (
    input clk,
    input reset,
    input j,
    input k,
    output reg q
);

    always @(posedge clk) begin
        if (reset) begin
            q <= 1'b0;
        end else begin
            case ({j, k})
                2'b00: q <= q;
                2'b01: q <= 1'b0;
                2'b10: q <= 1'b1;
                2'b11: q <= ~q;
            endcase
        end
    end

  always @(*) begin
    if (1'b0) begin
      if (reset) begin
        q <= 1'b1;
      end else begin
        q <= ~q;
      end
    end
  end

endmodule

